// Paste this entire file into the "Build review request" Code node in n8n.
// Keep in sync with reviewer/rubric.md.
// The reviewer model. Reads REVIEWER_MODEL from the env when the n8n node has
// env access, else the default below. (config.example documents it.)
const REVIEWER_MODEL =
  (typeof process !== 'undefined' && process.env && process.env.REVIEWER_MODEL) ||
  'claude-sonnet-4-6';
const RUBRIC = `You are the reviewer in a personal agent pipeline. A Claude Code work session has just ended. You receive evidence: repo, branch, last commit, diff stat, uncommitted file names, test output if any, and the project's tracker entry when one exists. The tracker entry contains the prompt this session was meant to execute, including a Done when line. Your job is triage, not full code review. Reply with JSON only, no prose, no markdown fences.

Verdicts:
- pass: work looks complete and safe, evidence supports the claim.
- revise: something concrete is wrong or unfinished and a fresh session could fix it without the human. You must write the fix prompt.
- escalate: a human decision is required, or policy forces it.

Judging against intent:
- When a tracker entry is present, judge the evidence against its Task and Done when lines. If the evidence satisfies Done when, scope is resolved: never escalate to ask whether the task was the whole task.
- When no tracker entry exists, say so in the summary and judge the work on its own terms. Prefer pass or revise over escalate for ordinary ambiguity in untracked repos.
- Uncommitted files are not by themselves escalation-worthy. Escalate for them only if a filename suggests secrets (.env, key, pem, token, credentials) or the diff touches auth.

Infrastructure exits are not broken environments. When end_reason is runner-recovery, the runner closed the session, not a /wrap, and a test_output that begins with RUNNER: is the runner's note rather than a test result. It means the session may have been cut short by infrastructure: an API overload or 5xx, a usage limit, or the harness exiting before the wrap hook fired. Do not read that note as a broken environment, a broken repo, or a failed setup, and do not treat an empty diff or absent commits as proof the work was bad: nothing was attempted, or the work never reached a commit. Judge the real commits, diff and tests on their merits. If this session's commits and a real diff show the task done, pass; if nothing was committed, prefer revise with a fix prompt that restates the original task and its Done when so a later session retries it. Escalate only if the original task itself forces it under the policy below, never because the runner reported the exit.

Always escalate, regardless of confidence, when the work touches money, payments, billing or transfers; anything deployed, published, sent or public-facing; credentials, secrets or auth; destructive or hard-to-reverse operations; the evidence contradicts the tracker entry's task; the project has already failed review repeatedly, meaning the tracker entry's Log shows two or more prior reviewer 'revise' cycles, since a task that keeps failing review needs a human, not another automatic retry; the session modifies the legwork pipeline itself, meaning the repo under review is legwork and the diff touches its hooks, reviewer rubric, n8n workflow or dashboard build script (scripts/ or reviewer/), since self modification of the pipeline always escalates; or the diff is empty while the commit claims real work. Never pass on prose alone.

session_commits lists the commits made during this session; attribute only those to the session. last_commit may predate the session and must not be judged as this session's work. Weigh evidence over narrative. When torn between pass and revise, choose revise. When torn between revise and escalate, choose escalate.

Output schema:
{"verdict":"pass|revise|escalate","confidence":0.0,"summary":"one line","reasons":["short"],"fix_prompt":"only for revise: complete cold-start prompt (context pointer, one task, Done when line, final step runs /wrap)","decision_brief":{"attempted":"one line","uncertain":"one line","options":["A. ...","B. ..."],"recommendation":"one line that names exactly one option letter"}}
Include fix_prompt only for revise. Include decision_brief only for escalate. The brief must be answerable with one letter, and the recommendation must name exactly one letter.`;

const p = $json.body || $json;

const evidence = [
  `repo: ${p.repo || 'unknown'}`,
  `branch: ${p.branch || 'unknown'}`,
  `last_commit: ${p.last_commit || 'none'}`,
  `uncommitted_files: ${p.uncommitted_files || '0'}`,
  `end_reason: ${p.end_reason || 'normal'}`,
  '',
  'uncommitted file names:',
  p.uncommitted_list || '(none)',
  '',
  'commits made this session:',
  p.session_commits || '(none recorded)',
  '',
  'diff_stat:',
  p.diff_stat || '(empty)',
  '',
  'test_output:',
  p.test_output || '(none provided)',
  '',
  'tracker entry (the prompt this session was meant to execute):',
  p.tracker_entry || '(no tracker entry: untracked repo)'
].join('\n');

return [{
  json: {
    evidence: p,
    request: {
      model: REVIEWER_MODEL,
      max_tokens: 1500,
      system: RUBRIC,
      messages: [{ role: 'user', content: `Session evidence:\n\n${evidence}` }]
    }
  }
}];

const evidence = $('Build review request').first().json.evidence || {};
const repo = evidence.repo || 'unknown repo';

let verdict = {
  verdict: 'escalate',
  confidence: 0,
  summary: 'Reviewer output could not be parsed. Failing safe.',
  reasons: ['parse failure'],
  decision_brief: {
    attempted: 'Automated review of the last session.',
    uncertain: 'The reviewer reply was not valid JSON.',
    options: ['A. Check the n8n execution log.', 'B. Re-run the review.'],
    recommendation: 'A.'
  }
};

try {
  const blocks = $json.content || [];
  const text = blocks.filter(b => b.type === 'text').map(b => b.text).join('\n');
  const clean = text.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(clean);
  if (['pass', 'revise', 'escalate'].includes(parsed.verdict)) {
    verdict = parsed;
  }
} catch (e) {
  // fall through to the fail-safe escalate above
}

const pct = Math.round((verdict.confidence || 0) * 100);
let message_text = '';

if (verdict.verdict === 'pass') {
  message_text = `PASS  ${repo}\n${verdict.summary} (${pct}%)`;
} else if (verdict.verdict === 'revise') {
  message_text = `REVISE  ${repo}\n${verdict.summary}\n\n` +
    `Why: ${(verdict.reasons || []).join('; ')}\n\n` +
    `Fix prompt (queued for next session):\n${verdict.fix_prompt || '(missing)'}`;
} else {
  const b = verdict.decision_brief || {};
  message_text = `NEEDS YOU  ${repo}\n\n` +
    `Attempted: ${b.attempted || verdict.summary}\n` +
    `Uncertain: ${b.uncertain || ''}\n\n` +
    `${(b.options || []).join('\n')}\n\n` +
    `Recommendation: ${b.recommendation || ''}\n\nReply with a letter.`;
}

return [{ json: { ...verdict, repo, message_text } }];

// Append one line per verdict to reviewer/verdicts.jsonl on the remote.
// The pass authority decision (silent passes) gets made on this record
// instead of memory. Append-only. A rare concurrent-write sha race loses
// one line, which is acceptable for calibration evidence.
const v = $('Parse verdict').first().json;
const evidence = ($('Build review request').first().json || {}).evidence || {};
const gh = $json;
const exists = gh && typeof gh.content === 'string' && gh.sha;
const raw = exists ? Buffer.from(String(gh.content).replace(/\s/g, ''), 'base64').toString('utf8') : '';
const line = JSON.stringify({
  ts: new Date().toISOString(),
  date: new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/London' }),
  repo: v.repo || 'unknown',
  verdict: v.verdict,
  confidence: v.confidence,
  summary: v.summary,
  end_reason: evidence.end_reason || '',
  source: evidence.source || '',
  session_id: evidence.session_id || ''
});
const content = (raw ? raw.replace(/\n*$/, '\n') : '') + line + '\n';
const body = {
  message: 'reviewer: ledger ' + (v.verdict || '?') + ' ' + (v.repo || 'unknown'),
  content: Buffer.from(content, 'utf8').toString('base64'),
  branch: 'main'
};
if (exists) body.sha = gh.sha;
return [{ json: { body: JSON.stringify(body) } }];

// The reviewer said escalate; make the project file say so too. Until
// this write lands an escalation exists only as a Telegram letter and the
// dashboard keeps showing the stale status (the stale-status case). Only
// in-flight states flip; done and icebox are never resurrected, and an
// untracked repo (no project file) is skipped.
const v = $('Parse verdict').first().json;
const gh = $json;
const exists = gh && typeof gh.content === 'string' && gh.sha;
if (!exists) {
  return [{ json: { writable: false, reason: 'no tracker file for ' + (v.repo || 'unknown') } }];
}
const raw = Buffer.from(String(gh.content).replace(/\s/g, ''), 'base64').toString('utf8');
if (!/^status:[ \t]*(queued|running|review)[ \t]*$/m.test(raw)) {
  return [{ json: { writable: false, reason: 'status already escalated or terminal' } }];
}
const date = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/London' });
let edited = raw.replace(/^status:[ \t]*(queued|running|review)[ \t]*$/m, 'status: escalated');
edited = edited.replace(/^updated:.*$/m, 'updated: ' + date);
const logLine = '- ' + date + ': Reviewer escalated: ' + String(v.summary || '').slice(0, 180).replace(/\n/g, ' ');
let withLog = edited.replace(/(##[ \t]*Log[^\n]*\n+)/, function (m) { return m + logLine + '\n'; });
if (withLog === edited) withLog = edited.replace(/\s+$/, '') + '\n\n## Log\n\n' + logLine + '\n';
const body = {
  message: 'reviewer: escalate ' + (v.repo || 'unknown'),
  content: Buffer.from(withLog, 'utf8').toString('base64'),
  sha: gh.sha,
  branch: 'main'
};
return [{ json: { writable: true, body: JSON.stringify(body), repo: v.repo } }];

// A pass verdict means the wrapped prompt is good to run again. Flip
// review to queued on the remote so the runner can fire the project
// without a human reply. Only review flips: running means a session is
// still in flight, escalated waits on a human letter, done and icebox
// are never resurrected, and an untracked repo (no project file) is
// skipped. The Next prompt block is kept exactly as wrapped.
const v = $('Parse verdict').first().json;
const gh = $json;
const exists = gh && typeof gh.content === 'string' && gh.sha;
if (!exists) {
  return [{ json: { writable: false, reason: 'no tracker file for ' + (v.repo || 'unknown') } }];
}
const raw = Buffer.from(String(gh.content).replace(/\s/g, ''), 'base64').toString('utf8');
if (!/^status:[ \t]*review[ \t]*$/m.test(raw)) {
  return [{ json: { writable: false, reason: 'status is not review' } }];
}
const date = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/London' });
let edited = raw.replace(/^status:[ \t]*review[ \t]*$/m, 'status: queued');
edited = edited.replace(/^updated:.*$/m, 'updated: ' + date);
const logLine = '- ' + date + ': Reviewer passed: ' +
  String(v.summary || '').slice(0, 180).replace(/\n/g, ' ') +
  ' Requeued with the wrapped prompt.';
let withLog = edited.replace(/(##[ \t]*Log[^\n]*\n+)/, function (m) { return m + logLine + '\n'; });
if (withLog === edited) withLog = edited.replace(/\s+$/, '') + '\n\n## Log\n\n' + logLine + '\n';
const body = {
  message: 'reviewer: pass ' + (v.repo || 'unknown'),
  content: Buffer.from(withLog, 'utf8').toString('base64'),
  sha: gh.sha,
  branch: 'main'
};
return [{ json: { writable: true, body: JSON.stringify(body), repo: v.repo } }];

// A revise verdict carries a fix prompt. Install it as the Next prompt
// and flip review to queued so the runner fires the fix without a human
// reply. Only review flips, untracked repos are skipped, and a revise
// with no readable fix prompt writes nothing: the Telegram letter still
// goes out and reply capture can install the prompt from the letter.
const v = $('Parse verdict').first().json;
const gh = $json;
const exists = gh && typeof gh.content === 'string' && gh.sha;
if (!exists) {
  return [{ json: { writable: false, reason: 'no tracker file for ' + (v.repo || 'unknown') } }];
}
const fix = String(v.fix_prompt || '').replace(/```[a-zA-Z]*\n?/g, '').replace(/```/g, '').trim();
if (!fix) {
  return [{ json: { writable: false, reason: 'revise verdict without a readable fix prompt' } }];
}
const raw = Buffer.from(String(gh.content).replace(/\s/g, ''), 'base64').toString('utf8');
if (!/^status:[ \t]*review[ \t]*$/m.test(raw)) {
  return [{ json: { writable: false, reason: 'status is not review' } }];
}
const date = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/London' });
let edited = raw.replace(/^status:[ \t]*review[ \t]*$/m, 'status: queued');
edited = edited.replace(/^updated:.*$/m, 'updated: ' + date);
const promptBlock = '```text\n' + fix + '\n```';
let withPrompt = edited.replace(/(##[ \t]*Next prompt[ \t]*\n+)```[\s\S]*?```/,
  function (m, p1) { return p1 + promptBlock; });
if (withPrompt === edited) {
  withPrompt = edited.replace(/\s+$/, '') + '\n\n## Next prompt\n\n' + promptBlock + '\n';
}
const logLine = '- ' + date + ': Reviewer revise: ' +
  String(v.summary || '').slice(0, 180).replace(/\n/g, ' ') +
  ' Fix prompt installed and requeued.';
let withLog = withPrompt.replace(/(##[ \t]*Log[^\n]*\n+)/, function (m) { return m + logLine + '\n'; });
if (withLog === withPrompt) withLog = withPrompt.replace(/\s+$/, '') + '\n\n## Log\n\n' + logLine + '\n';
const body = {
  message: 'reviewer: revise ' + (v.repo || 'unknown'),
  content: Buffer.from(withLog, 'utf8').toString('base64'),
  sha: gh.sha,
  branch: 'main'
};
return [{ json: { writable: true, body: JSON.stringify(body), repo: v.repo } }];
